    __asm__ volatile(
        /* Input arguments are already in the right locations */
        "syscall"
        : "=a" (result)
        : "a" (syscall_num),
          "D" (arg1),
          "S" (arg2),
          "d" (arg3),
          "r" (arg4)   /* r10 */,
          "r" (arg5)   /* r8 */,
          "r" (arg6)   /* r9 */
        : "rcx", "r11", "memory"
    );

    /* Check for error and set errno */
    if (result < 0 && result > -4096) {
        errno = -result;
        return -1;
    }

    return result;

}


