#!/usr/bin/env node
'use strict';
// MIPS32r2 (o32, little-endian) userspace interpreter for doomgeneric_mips.
// Loads the static ELF, emulates the CPU + FPU, and services the custom
// syscall ABI used by my_stdlib.c (syscall# in $v0, args in $a0-$a3/$t0-$t1).

const fs = require('fs');
const path = require('path');

const ELF_PATH = process.argv[2] || path.join(__dirname, 'doomgeneric_mips');

// ---------------------------------------------------------------------------
// Memory
// ---------------------------------------------------------------------------
const MEM_SIZE = 0x40800000; // ~1.08 GB, covers text/data/bss and the stack
const STACK_TOP = 0x40700000; // above bss end (~0x404b6790), below MEM_SIZE

const mem = new ArrayBuffer(MEM_SIZE);
const u8 = new Uint8Array(mem);
const dv = new DataView(mem);

function rd8(a) { return u8[a]; }
function rd8s(a) { return (u8[a] << 24) >> 24; }
function rd16(a) { return dv.getUint16(a, true); }
function rd16s(a) { return dv.getInt16(a, true); }
function rd32(a) { return dv.getInt32(a, true); }
function rd32u(a) { return dv.getUint32(a, true); }
function wr8(a, v) { u8[a] = v & 0xff; }
function wr16(a, v) { dv.setUint16(a, v & 0xffff, true); }
function wr32(a, v) { dv.setUint32(a, v >>> 0, true); }

function readCString(a) {
  let s = '';
  a = a >>> 0;
  while (u8[a] !== 0) { s += String.fromCharCode(u8[a]); a++; }
  return s;
}

// ---------------------------------------------------------------------------
// ELF loader
// ---------------------------------------------------------------------------
function loadElf(file) {
  const buf = fs.readFileSync(file);
  if (buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46)
    throw new Error('not an ELF file');
  const entry = buf.readUInt32LE(24);
  const phoff = buf.readUInt32LE(28);
  const phentsize = buf.readUInt16LE(42);
  const phnum = buf.readUInt16LE(44);
  for (let i = 0; i < phnum; i++) {
    const off = phoff + i * phentsize;
    const type = buf.readUInt32LE(off);
    if (type !== 1) continue; // PT_LOAD
    const p_offset = buf.readUInt32LE(off + 4);
    const p_vaddr = buf.readUInt32LE(off + 8);
    const p_filesz = buf.readUInt32LE(off + 16);
    const p_memsz = buf.readUInt32LE(off + 20);
    for (let j = 0; j < p_filesz; j++) u8[p_vaddr + j] = buf[p_offset + j];
    // remainder of memsz is bss, already zero
    void p_memsz;
  }
  return entry;
}

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const R = new Int32Array(32);
let HI = 0, LO = 0;
const FP = new Uint32Array(34); // FR=0: even/odd pairs form doubles
let FCC = 0;                    // FP condition code 0

const fb = new ArrayBuffer(8);
const f32 = new Float32Array(fb);
const f64 = new Float64Array(fb);
const fu32 = new Uint32Array(fb);
function getS(r) { fu32[0] = FP[r]; return f32[0]; }
function setS(r, v) { f32[0] = v; FP[r] = fu32[0]; }
function getD(r) { fu32[0] = FP[r]; fu32[1] = FP[r + 1]; return f64[0]; }
function setD(r, v) { f64[0] = v; FP[r] = fu32[0]; FP[r + 1] = fu32[1]; }

// ---------------------------------------------------------------------------
// Syscalls (numbers per my_stdlib.c: x86-64-style numbering)
// ---------------------------------------------------------------------------
const SYS = {
  read: 0, write: 1, open: 2, close: 3, lseek: 8, nanosleep: 35,
  fsync: 74, rename: 82, mkdir: 83, unlink: 87, gettimeofday: 96,
  exit: 60, time: 201,
};
const fdPos = new Map(); // guest fd -> file position

function openFlagsToNode(flags) {
  const acc = flags & 3;
  const create = (flags & 64) !== 0;
  const trunc = (flags & 512) !== 0;
  const append = (flags & 1024) !== 0;
  if (append) return acc === 2 ? 'a+' : 'a';
  if (acc === 0) return 'r';
  if (acc === 2) return create ? (trunc ? 'w+' : 'r+') : 'r+';
  // write-only
  return create ? (trunc ? 'w' : 'r+') : 'r+';
}

class ExitSignal { constructor(code) { this.code = code; } }

function doSyscall() {
  const num = R[2] | 0;
  const a0 = R[4] | 0, a1 = R[5] | 0, a2 = R[6] | 0, a3 = R[7] | 0;
  switch (num) {
    case SYS.write: {
      const fd = a0, ptr = a1 >>> 0, len = a2 >>> 0;
      if (fd === 1 || fd === 2) {
        const b = Buffer.from(mem, ptr, len);
        (fd === 1 ? process.stdout : process.stderr).write(Buffer.from(b));
        return len;
      }
      try {
        let pos = fdPos.get(fd); if (pos === undefined) pos = 0;
        const b = Buffer.from(mem, ptr, len);
        const n = fs.writeSync(fd, b, 0, len, pos);
        fdPos.set(fd, pos + n);
        return n;
      } catch (e) { return -1; }
    }
    case SYS.read: {
      const fd = a0, ptr = a1 >>> 0, len = a2 >>> 0;
      if (fd === 0) return 0;
      try {
        let pos = fdPos.get(fd); if (pos === undefined) pos = 0;
        const b = Buffer.from(mem, ptr, len);
        const n = fs.readSync(fd, b, 0, len, pos);
        fdPos.set(fd, pos + n);
        return n;
      } catch (e) { return -1; }
    }
    case SYS.open: {
      const name = readCString(a0);
      const flags = a1 | 0;
      try {
        const fd = fs.openSync(resolvePath(name), openFlagsToNode(flags), 0o644);
        fdPos.set(fd, 0);
        return fd;
      } catch (e) { return -2; /* -ENOENT */ }
    }
    case SYS.close: {
      const fd = a0;
      if (fd <= 2) return 0;
      try { fs.closeSync(fd); } catch (e) {}
      fdPos.delete(fd);
      return 0;
    }
    case SYS.lseek: {
      const fd = a0, off = a1 | 0, whence = a2 | 0;
      let pos = fdPos.get(fd); if (pos === undefined) pos = 0;
      let np;
      if (whence === 0) np = off;
      else if (whence === 1) np = pos + off;
      else { // SEEK_END
        let sz = 0;
        try { sz = fs.fstatSync(fd).size; } catch (e) {}
        np = sz + off;
      }
      if (np < 0) return -1;
      fdPos.set(fd, np);
      return np;
    }
    case SYS.fsync: return 0;
    case SYS.mkdir: {
      const name = readCString(a0);
      try { fs.mkdirSync(resolvePath(name)); return 0; } catch (e) { return -1; }
    }
    case SYS.unlink: {
      const name = readCString(a0);
      try { fs.unlinkSync(resolvePath(name)); return 0; } catch (e) { return -1; }
    }
    case SYS.rename: {
      try { fs.renameSync(resolvePath(readCString(a0)), resolvePath(readCString(a1))); return 0; }
      catch (e) { return -1; }
    }
    case SYS.time: {
      const t = Math.floor(Date.now() / 1000);
      if (a0 !== 0) wr32(a0 >>> 0, t);
      return t;
    }
    case SYS.gettimeofday: {
      if (a0 !== 0) {
        const ms = Date.now();
        wr32(a0 >>> 0, Math.floor(ms / 1000));
        wr32((a0 + 4) >>> 0, (ms % 1000) * 1000);
      }
      return 0;
    }
    case SYS.nanosleep: return 0;
    case SYS.exit: throw new ExitSignal(a0 | 0);
    default:
      process.stderr.write('unhandled syscall ' + num + '\n');
      return -1;
  }
}

function resolvePath(name) {
  if (path.isAbsolute(name)) return name;
  // Prefer cwd; fall back to the directory containing the ELF (where doom.wad lives).
  if (fs.existsSync(name)) return name;
  const alt = path.join(path.dirname(path.resolve(ELF_PATH)), name);
  if (fs.existsSync(alt)) return alt;
  return name;
}

// ---------------------------------------------------------------------------
// Interpreter
// ---------------------------------------------------------------------------
function run(entry) {
  let PC = entry >>> 0;
  let nPC = (entry + 4) >>> 0;
  R[29] = STACK_TOP | 0;   // $sp
  R[28] = 0;               // $gp (unused as global base here)
  R[31] = 0;               // $ra

  let icount = 0;
  for (;;) {
    R[0] = 0;
    const cur = PC;
    const inst = rd32u(cur);
    PC = nPC;
    nPC = (nPC + 4) >>> 0;
    icount++;

    const op = inst >>> 26;
    const rs = (inst >>> 21) & 31;
    const rt = (inst >>> 16) & 31;
    const rd = (inst >>> 11) & 31;
    const sa = (inst >>> 6) & 31;
    const funct = inst & 63;
    const imm = inst & 0xffff;
    const simm = (imm << 16) >> 16;

    switch (op) {
      case 0x00: { // SPECIAL
        switch (funct) {
          case 0x00: R[rd] = R[rt] << sa; break;             // sll
          case 0x02: // srl / rotr
            if ((inst >>> 21) & 1) R[rd] = (R[rt] >>> sa) | (R[rt] << (32 - sa) & (sa ? -1 : 0));
            else R[rd] = R[rt] >>> sa;
            if (((inst >>> 21) & 1) && sa === 0) R[rd] = R[rt];
            break;
          case 0x03: R[rd] = R[rt] >> sa; break;             // sra
          case 0x04: R[rd] = R[rt] << (R[rs] & 31); break;   // sllv
          case 0x06: { // srlv / rotrv
            const s = R[rs] & 31;
            if ((inst >>> 6) & 1) R[rd] = s ? ((R[rt] >>> s) | (R[rt] << (32 - s))) : R[rt];
            else R[rd] = R[rt] >>> s;
            break;
          }
          case 0x07: R[rd] = R[rt] >> (R[rs] & 31); break;   // srav
          case 0x08: nPC = R[rs] >>> 0; break;               // jr
          case 0x09: R[rd] = (cur + 8) >>> 0; nPC = R[rs] >>> 0; break; // jalr
          case 0x0a: if (R[rt] === 0) R[rd] = R[rs]; break;  // movz
          case 0x0b: if (R[rt] !== 0) R[rd] = R[rs]; break;  // movn
          case 0x0c: doSyscall(); R[2] = R[2]; break;        // syscall (return already in R[2])
          case 0x0d: throw new ExitSignal(0);                // break
          case 0x0f: break;                                  // sync
          case 0x10: R[rd] = HI; break;                      // mfhi
          case 0x11: HI = R[rs]; break;                      // mthi
          case 0x12: R[rd] = LO; break;                      // mflo
          case 0x13: LO = R[rs]; break;                      // mtlo
          case 0x18: { // mult
            const r = BigInt(R[rs]) * BigInt(R[rt]);
            LO = Number(BigInt.asIntN(32, r));
            HI = Number(BigInt.asIntN(32, r >> 32n));
            break;
          }
          case 0x19: { // multu
            const r = BigInt(R[rs] >>> 0) * BigInt(R[rt] >>> 0);
            LO = Number(BigInt.asIntN(32, r));
            HI = Number(BigInt.asIntN(32, r >> 32n));
            break;
          }
          case 0x1a: { // div
            const b = R[rt];
            if (b !== 0) {
              const A = BigInt(R[rs]), B = BigInt(b);
              LO = Number(BigInt.asIntN(32, A / B));
              HI = Number(BigInt.asIntN(32, A % B));
            } else { LO = 0; HI = 0; }
            break;
          }
          case 0x1b: { // divu
            const b = R[rt] >>> 0;
            if (b !== 0) {
              const A = BigInt(R[rs] >>> 0), B = BigInt(b);
              LO = Number(BigInt.asIntN(32, A / B));
              HI = Number(BigInt.asIntN(32, A % B));
            } else { LO = 0; HI = 0; }
            break;
          }
          case 0x20: R[rd] = (R[rs] + R[rt]) | 0; break;     // add
          case 0x21: R[rd] = (R[rs] + R[rt]) | 0; break;     // addu
          case 0x22: R[rd] = (R[rs] - R[rt]) | 0; break;     // sub
          case 0x23: R[rd] = (R[rs] - R[rt]) | 0; break;     // subu
          case 0x24: R[rd] = R[rs] & R[rt]; break;           // and
          case 0x25: R[rd] = R[rs] | R[rt]; break;           // or
          case 0x26: R[rd] = R[rs] ^ R[rt]; break;           // xor
          case 0x27: R[rd] = ~(R[rs] | R[rt]); break;        // nor
          case 0x2a: R[rd] = (R[rs] < R[rt]) ? 1 : 0; break; // slt
          case 0x2b: R[rd] = ((R[rs] >>> 0) < (R[rt] >>> 0)) ? 1 : 0; break; // sltu
          case 0x34: if (R[rs] === R[rt]) throw new Error('teq trap at 0x' + cur.toString(16)); break; // teq
          case 0x30: break; // tge (no-op unless trap; ignore)
          case 0x36: break; // tne guard
          default: throw new Error('unknown SPECIAL funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
        }
        break;
      }
      case 0x01: { // REGIMM
        switch (rt) {
          case 0x00: if (R[rs] < 0) nPC = (cur + 4 + (simm << 2)) >>> 0; break; // bltz
          case 0x01: if (R[rs] >= 0) nPC = (cur + 4 + (simm << 2)) >>> 0; break; // bgez
          case 0x10: { const t = R[rs] < 0; R[31] = (cur + 8) >>> 0; if (t) nPC = (cur + 4 + (simm << 2)) >>> 0; break; } // bltzal
          case 0x11: { const t = R[rs] >= 0; R[31] = (cur + 8) >>> 0; if (t) nPC = (cur + 4 + (simm << 2)) >>> 0; break; } // bgezal
          default: throw new Error('unknown REGIMM rt 0x' + rt.toString(16) + ' @0x' + cur.toString(16));
        }
        break;
      }
      case 0x02: nPC = (((cur + 4) & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break; // j
      case 0x03: R[31] = (cur + 8) >>> 0; nPC = (((cur + 4) & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break; // jal
      case 0x04: if (R[rs] === R[rt]) nPC = (cur + 4 + (simm << 2)) >>> 0; break; // beq
