        } else if (funct === 0x20) { R[rd] = Math.clz32(R[rs]); } // clz
        else throw new Error('unknown SPECIAL2 funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
      case 0x1f: { // SPECIAL3
        if (funct === 0x00) { // ext
          const pos = sa, size = rd + 1;
          const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
          R[rt] = (R[rs] >>> pos) & mask;
        } else if (funct === 0x04) { // ins
          const pos = sa, msb = rd, size = msb - pos + 1;
          const mask = ((size >= 32 ? 0xffffffff : ((1 << size) - 1)) << pos) >>> 0;
          R[rt] = ((R[rt] & ~mask) | ((R[rs] << pos) & mask)) | 0;
        } else if (funct === 0x20) { // BSHFL
          const v = R[rt] >>> 0;
          if (sa === 0x02) R[rd] = (((v & 0x00ff00ff) << 8) | ((v >>> 8) & 0x00ff00ff)) | 0; // wsbh
          else if (sa === 0x10) R[rd] = (v << 24) >> 24; // seb
          else if (sa === 0x18) R[rd] = (v << 16) >> 16; // seh
          else throw new Error('unknown BSHFL sa 0x' + sa.toString(16) + ' @0x' + cur.toString(16));
        } else throw new Error('unknown SPECIAL3 funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
      case 0x11: { // COP1 (FPU)
        const fmt = rs; const ft = rt; const fs = rd; const fd = sa;
        if (fmt === 0x00) R[rt] = FP[fs] | 0;             // mfc1
        else if (fmt === 0x04) FP[fs] = R[rt] >>> 0;      // mtc1
        else if (fmt === 0x03) R[rt] = FP[fs + 1] | 0;    // mfhc1
        else if (fmt === 0x07) FP[fs + 1] = R[rt] >>> 0;  // mthc1
        else if (fmt === 0x02) R[rt] = (FCC << 23);       // cfc1 (FCSR)
        else if (fmt === 0x06) FCC = (R[rt] >>> 23) & 1;  // ctc1
        else if (fmt === 0x08) { // BC1
          const tf = (rt >>> 0) & 1; const take = (FCC === tf);
          if (take) nPC = (cur + 4 + (simm << 2)) >>> 0;
        } else if (fmt === 0x10) { // single
          switch (funct) {
            case 0x00: setS(fd, getS(fs) + getS(ft)); break;
            case 0x01: setS(fd, getS(fs) - getS(ft)); break;
            case 0x02: setS(fd, getS(fs) * getS(ft)); break;
            case 0x03: setS(fd, getS(fs) / getS(ft)); break;
            case 0x04: setS(fd, Math.sqrt(getS(fs))); break;
            case 0x05: setS(fd, Math.abs(getS(fs))); break;
            case 0x06: FP[fd] = FP[fs]; break;             // mov.s
            case 0x07: setS(fd, -getS(fs)); break;         // neg.s
            case 0x11: { const tf = (ft & 1); if (FCC === tf) FP[fd] = FP[fs]; break; } // movcf.s
            case 0x21: setD(fd, getS(fs)); break;          // cvt.d.s
            case 0x24: FP[fd] = (Math.trunc(getS(fs)) | 0) >>> 0; break; // cvt.w.s (RZ default enough)
            case 0x0d: FP[fd] = (Math.trunc(getS(fs)) | 0) >>> 0; break; // trunc.w.s
            case 0x32: FCC = (getS(fs) === getS(ft)) ? 1 : 0; break; // c.eq.s
            case 0x34: FCC = (getS(fs) < getS(ft)) ? 1 : 0; break;  // c.olt.s
            case 0x3c: FCC = (getS(fs) < getS(ft)) ? 1 : 0; break;  // c.lt.s
            case 0x3e: FCC = (getS(fs) <= getS(ft)) ? 1 : 0; break; // c.le.s
            case 0x36: FCC = (getS(fs) <= getS(ft)) ? 1 : 0; break; // c.ole.s
            default: throw new Error('unknown cop1.s funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else if (fmt === 0x11) { // double
          switch (funct) {
            case 0x00: setD(fd, getD(fs) + getD(ft)); break;
            case 0x01: setD(fd, getD(fs) - getD(ft)); break;
            case 0x02: setD(fd, getD(fs) * getD(ft)); break;
            case 0x03: setD(fd, getD(fs) / getD(ft)); break;
            case 0x04: setD(fd, Math.sqrt(getD(fs))); break;
            case 0x05: setD(fd, Math.abs(getD(fs))); break;
            case 0x06: FP[fd] = FP[fs]; FP[fd + 1] = FP[fs + 1]; break; // mov.d
            case 0x07: setD(fd, -getD(fs)); break;         // neg.d
            case 0x11: { const tf = (ft & 1); if (FCC === tf) { FP[fd] = FP[fs]; FP[fd + 1] = FP[fs + 1]; } break; } // movcf.d
            case 0x20: setS(fd, getD(fs)); break;          // cvt.s.d
            case 0x24: FP[fd] = (Math.trunc(getD(fs)) | 0) >>> 0; break; // cvt.w.d
            case 0x0d: FP[fd] = (Math.trunc(getD(fs)) | 0) >>> 0; break; // trunc.w.d
            case 0x32: FCC = (getD(fs) === getD(ft)) ? 1 : 0; break; // c.eq.d
            case 0x34: FCC = (getD(fs) < getD(ft)) ? 1 : 0; break;  // c.olt.d
            case 0x3c: FCC = (getD(fs) < getD(ft)) ? 1 : 0; break;  // c.lt.d
            case 0x3e: FCC = (getD(fs) <= getD(ft)) ? 1 : 0; break; // c.le.d
            case 0x36: FCC = (getD(fs) <= getD(ft)) ? 1 : 0; break; // c.ole.d
            default: throw new Error('unknown cop1.d funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else if (fmt === 0x14) { // word
          switch (funct) {
            case 0x20: setS(fd, FP[fs] | 0); break;        // cvt.s.w
            case 0x21: setD(fd, FP[fs] | 0); break;        // cvt.d.w
            default: throw new Error('unknown cop1.w funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else throw new Error('unknown COP1 fmt 0x' + fmt.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
      // -------- loads --------
      case 0x20: R[rt] = rd8s((R[rs] + simm) >>> 0); break;   // lb
      case 0x21: R[rt] = rd16s((R[rs] + simm) >>> 0); break;  // lh
      case 0x23: R[rt] = rd32((R[rs] + simm) >>> 0); break;   // lw
      case 0x24: R[rt] = rd8((R[rs] + simm) >>> 0); break;    // lbu
      case 0x25: R[rt] = rd16((R[rs] + simm) >>> 0); break;   // lhu
      case 0x22: { // lwl
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const w = rd32u(addr & ~3);
        const cur2 = R[rt] >>> 0;
        let v;
        if (b === 0) v = (cur2 & 0x00ffffff) | (w << 24);
        else if (b === 1) v = (cur2 & 0x0000ffff) | (w << 16);
        else if (b === 2) v = (cur2 & 0x000000ff) | (w << 8);
        else v = w;
        R[rt] = v | 0;
        break;
      }
      case 0x26: { // lwr
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const w = rd32u(addr & ~3);
        const cur2 = R[rt] >>> 0;
        let v;
        if (b === 0) v = w;
        else if (b === 1) v = (cur2 & 0xff000000) | (w >>> 8);
        else if (b === 2) v = (cur2 & 0xffff0000) | (w >>> 16);
        else v = (cur2 & 0xffffff00) | (w >>> 24);
        R[rt] = v | 0;
        break;
      }
      // -------- stores --------
      case 0x28: wr8((R[rs] + simm) >>> 0, R[rt]); break;     // sb
      case 0x29: wr16((R[rs] + simm) >>> 0, R[rt]); break;    // sh
      case 0x2b: wr32((R[rs] + simm) >>> 0, R[rt]); break;    // sw
      case 0x2a: { // swl
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const base = addr & ~3; const w = rd32u(base); const s = R[rt] >>> 0;
        let v;
        if (b === 0) v = (w & 0xffffff00) | (s >>> 24);
        else if (b === 1) v = (w & 0xffff0000) | (s >>> 16);
        else if (b === 2) v = (w & 0xff000000) | (s >>> 8);
        else v = s;
        wr32(base, v);
        break;
      }
      case 0x2e: { // swr
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const base = addr & ~3; const w = rd32u(base); const s = R[rt] >>> 0;
        let v;
        if (b === 0) v = s;
        else if (b === 1) v = (w & 0x000000ff) | (s << 8);
        else if (b === 2) v = (w & 0x0000ffff) | (s << 16);
        else v = (w & 0x00ffffff) | (s << 24);
        wr32(base, v);
        break;
      }
      // -------- FP loads/stores --------
      case 0x31: FP[rt] = rd32u((R[rs] + simm) >>> 0); break;  // lwc1
      case 0x39: wr32((R[rs] + simm) >>> 0, FP[rt]); break;    // swc1
      case 0x35: { const a = (R[rs] + simm) >>> 0; FP[rt] = rd32u(a); FP[rt + 1] = rd32u(a + 4); break; } // ldc1
      case 0x3d: { const a = (R[rs] + simm) >>> 0; wr32(a, FP[rt]); wr32(a + 4, FP[rt + 1]); break; }     // sdc1
      case 0x33: break; // pref (no-op)
      default:
        throw new Error('unknown opcode 0x' + op.toString(16) + ' inst 0x' + inst.toString(16) + ' @0x' + cur.toString(16));
    }
  }
}

// ---------------------------------------------------------------------------
const entry = loadElf(ELF_PATH);
try {
  run(entry);
} catch (e) {
  if (e instanceof ExitSignal) {
    process.exit(e.code);
  }
  throw e;
}

