        } else if (funct === 0x20) { R[rd] = Math.clz32(R[rs]); } // clz
        else throw new Error('unknown SPECIAL2 funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
      case 0x1f: { // SPECIAL3
        if (funct === 0x00) { // ext
          const pos = sa, size = rd + 1;
          const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
          R[rt] = (R[rs] >>> pos) & mask;
        } else if (funct === 0x04) { // ins
          const pos = sa, msb = rd, size = msb - pos + 1;
          const mask = ((size >= 32 ? 0xffffffff : ((1 << size) - 1)) << pos) >>> 0;
          R[rt] = ((R[rt] & ~mask) | ((R[rs] << pos) & mask)) | 0;
        } else if (funct === 0x20) { // BSHFL
          const v = R[rt] >>> 0;
          if (sa === 0x02) R[rd] = (((v & 0x00ff00ff) << 8) | ((v >>> 8) & 0x00ff00ff)) | 0; // wsbh
          else if (sa === 0x10) R[rd] = (v << 24) >> 24; // seb
          else if (sa === 0x18) R[rd] = (v << 16) >> 16; // seh
          else throw new Error('unknown BSHFL sa 0x' + sa.toString(16) + ' @0x' + cur.toString(16));
