        else if (fmt === 0x03) R[rt] = FP[fs + 1] | 0;    // mfhc1
        else if (fmt === 0x07) FP[fs + 1] = R[rt] >>> 0;  // mthc1
        else if (fmt === 0x02) R[rt] = (FCC << 23);       // cfc1 (FCSR)
