            case 0x34: FCC = (getS(fs) < getS(ft)) ? 1 : 0; break;  // c.olt.s
            case 0x3c: FCC = (getS(fs) < getS(ft)) ? 1 : 0; break;  // c.lt.s
            case 0x3e: FCC = (getS(fs) <= getS(ft)) ? 1 : 0; break; // c.le.s
            case 0x36: FCC = (getS(fs) <= getS(ft)) ? 1 : 0; break; // c.ole.s
