          switch (funct) {
            case 0x20: setS(fd, FP[fs] | 0); break;        // cvt.s.w
            case 0x21: setD(fd, FP[fs] | 0); break;        // cvt.d.w
            default: throw new Error('unknown cop1.w funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else throw new Error('unknown COP1 fmt 0x' + fmt.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
