      case 0x20: R[rt] = rd8s((R[rs] + simm) >>> 0); break;   // lb
      case 0x21: R[rt] = rd16s((R[rs] + simm) >>> 0); break;  // lh
      case 0x23: R[rt] = rd32((R[rs] + simm) >>> 0); break;   // lw
      case 0x24: R[rt] = rd8((R[rs] + simm) >>> 0); break;    // lbu
      case 0x25: R[rt] = rd16((R[rs] + simm) >>> 0); break;   // lhu
      case 0x22: { // lwl
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const w = rd32u(addr & ~3);
        const cur2 = R[rt] >>> 0;
        let v;
        if (b === 0) v = (cur2 & 0x00ffffff) | (w << 24);
        else if (b === 1) v = (cur2 & 0x0000ffff) | (w << 16);
        else if (b === 2) v = (cur2 & 0x000000ff) | (w << 8);
        else v = w;
