        if (b === 0) v = w;
        else if (b === 1) v = (cur2 & 0xff000000) | (w >>> 8);
        else if (b === 2) v = (cur2 & 0xffff0000) | (w >>> 16);
        else v = (cur2 & 0xffffff00) | (w >>> 24);
        R[rt] = v | 0;
        break;
