          LO = Number(BigInt.asIntN(32, r)); HI = Number(BigInt.asIntN(32, r >> 32n));
        } else if (funct === 0x20) { R[rd] = Math.clz32(R[rs]); } // clz
        else throw new Error('unknown SPECIAL2 funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
