            case 0x11: { const tf = ft & 1; if (FCC === tf) { FP[fd] = FP[fs]; FP[fd + 1] = FP[fs + 1]; } break; } // movcf.d
            case 0x20: setS(fd, getD(fs)); break;          // cvt.s.d
            case 0x24: FP[fd] = (Math.trunc(getD(fs)) | 0) >>> 0; break; // cvt.w.d
            case 0x0d: FP[fd] = (Math.trunc(getD(fs)) | 0) >>> 0; break; // trunc.w.d
            case 0x32: FCC = (getD(fs) === getD(ft)) ? 1 : 0; break; // c.eq.d
            case 0x34: FCC = (getD(fs) < getD(ft)) ? 1 : 0; break;  // c.olt.d
            case 0x3c: FCC = (getD(fs) < getD(ft)) ? 1 : 0; break;  // c.lt.d
            case 0x3e: FCC = (getD(fs) <= getD(ft)) ? 1 : 0; break; // c.le.d
            case 0x36: FCC = (getD(fs) <= getD(ft)) ? 1 : 0; break; // c.ole.d
            default: throw new Error('unknown cop1.d funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else if (fmt === 0x14) { // word
          switch (funct) {
            case 0x20: setS(fd, FP[fs] | 0); break;        // cvt.s.w
            case 0x21: setD(fd, FP[fs] | 0); break;        // cvt.d.w
            default: throw new Error('unknown cop1.w funct 0x' + funct.toString(16) + ' @0x' + cur.toString(16));
          }
        } else throw new Error('unknown COP1 fmt 0x' + fmt.toString(16) + ' @0x' + cur.toString(16));
        break;
      }
      // -------- loads --------
      case 0x20: R[rt] = rd8s((R[rs] + simm) >>> 0); break;   // lb
      case 0x21: R[rt] = rd16s((R[rs] + simm) >>> 0); break;  // lh
      case 0x23: R[rt] = rd32((R[rs] + simm) >>> 0); break;   // lw
      case 0x24: R[rt] = rd8((R[rs] + simm) >>> 0); break;    // lbu
      case 0x25: R[rt] = rd16((R[rs] + simm) >>> 0); break;   // lhu
      case 0x22: { // lwl
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const w = rd32u(addr & ~3); const o = R[rt] >>> 0;
        let v;
        if (b === 0) v = (o & 0x00ffffff) | (w << 24);
        else if (b === 1) v = (o & 0x0000ffff) | (w << 16);
        else if (b === 2) v = (o & 0x000000ff) | (w << 8);
        else v = w;
        R[rt] = v | 0;
        break;
      }
      case 0x26: { // lwr
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const w = rd32u(addr & ~3); const o = R[rt] >>> 0;
        let v;
        if (b === 0) v = w;
        else if (b === 1) v = (o & 0xff000000) | (w >>> 8);
        else if (b === 2) v = (o & 0xffff0000) | (w >>> 16);
        else v = (o & 0xffffff00) | (w >>> 24);
        R[rt] = v | 0;
        break;
      }
      // -------- stores --------
      case 0x28: wr8((R[rs] + simm) >>> 0, R[rt]); break;     // sb
      case 0x29: wr16((R[rs] + simm) >>> 0, R[rt]); break;    // sh
      case 0x2b: wr32((R[rs] + simm) >>> 0, R[rt]); break;    // sw
      case 0x2a: { // swl
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const base = addr & ~3; const w = rd32u(base); const s = R[rt] >>> 0;
        let v;
        if (b === 0) v = (w & 0xffffff00) | (s >>> 24);
        else if (b === 1) v = (w & 0xffff0000) | (s >>> 16);
        else if (b === 2) v = (w & 0xff000000) | (s >>> 8);
        else v = s;
        wr32(base, v);
        break;
      }
      case 0x2e: { // swr
        const addr = (R[rs] + simm) >>> 0; const b = addr & 3;
        const base = addr & ~3; const w = rd32u(base); const s = R[rt] >>> 0;
        let v;
        if (b === 0) v = s;
        else if (b === 1) v = (w & 0x000000ff) | (s << 8);
        else if (b === 2) v = (w & 0x0000ffff) | (s << 16);
        else v = (w & 0x00ffffff) | (s << 24);
        wr32(base, v);
        break;
      }
      // -------- FP loads/stores --------
      case 0x31: FP[rt] = rd32u((R[rs] + simm) >>> 0); break;  // lwc1
      case 0x39: wr32((R[rs] + simm) >>> 0, FP[rt]); break;    // swc1
      case 0x35: { const a = (R[rs] + simm) >>> 0; FP[rt] = rd32u(a); FP[rt + 1] = rd32u(a + 4); break; } // ldc1
      case 0x3d: { const a = (R[rs] + simm) >>> 0; wr32(a, FP[rt]); wr32(a + 4, FP[rt + 1]); break; }     // sdc1
      case 0x33: break; // pref (no-op)
      default:
        throw new Error('unknown opcode 0x' + op.toString(16) + ' inst 0x' + inst.toString(16) + ' @0x' + cur.toString(16));
    }
  }
}

// ---------------------------------------------------------------------------
const entry = loadElf(ELF_PATH);
try {
  run(entry);
} catch (e) {
  if (e instanceof ExitSignal) process.exit(e.code);
  throw e;
}

